const settle = (
  outcome: { ok: true; result: SpawnResult } | { ok: false; error: Error },
) => {
  if (settled) return;
  settled = true;
  clearTimeout(timeoutId);
  options.signal?.removeEventListener("abort", onAbort);
  if (outcome.ok) {
    resolve(outcome.result);
  } else {
    reject(outcome.error);
  }

